// src/modules/tasks/routes.js
const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    let tasks = await tasksService.getAllTasks(projectId);
    if (req.query.status === 'done') {
      tasks = tasks.filter(task => task.status === 'done');
    }
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_INPUT', 'Name is required');
  }
  try {
    const projectId = req.params.projectId;
    const task = await tasksService.createTask(projectId, name);
    res.status(201).json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.patch('/:taskId', async (req, res) => {
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid task status');
  }
  try {
    const projectId = req.params.projectId;
    const taskId = req.params.taskId;
    const updatedTask = await tasksService.updateTaskStatus(projectId, taskId, status);
    if (!updatedTask) {
      return sendError(res, 404, 'NOT_FOUND', 'Task not found');
    }
    res.json({ task: updatedTask });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');

let tasksStore = [];

async function getAllTasks(projectId) {
  return tasksStore.filter(task => task.projectId === projectId);
}

async function createTask(projectId, name) {
  const task = {
    id: randomUUID(),
    projectId,
    name,
    status: 'todo',
  };
  tasksStore.push(task);
  return task;
}

async function updateTaskStatus(projectId, taskId, status) {
  const taskIndex = tasksStore.findIndex(task => task.projectId === projectId && task.id === taskId);
  if (taskIndex === -1) {
    return null;
  }
  tasksStore[taskIndex].status = status;
  return tasksStore[taskIndex];
}

module.exports = {
  getAllTasks,
  createTask,
  updateTaskStatus,
};

